function generatePlaywrightSelectors() {
  // Function to generate a simple selector for an element
  function createSelector(element) {
    let selectorParts = [];

    if (element.id) {
      return `id=${element.id}`;
    }

    selectorParts.push(element.tagName.toLowerCase());

    if (element.className) {
      selectorParts.push(
        '.' + Array.from(element.classList).join('.')
      );
    }

    // Calculate the nth-of-type position
    let childIndex = 1;
    let prevSibling = element.previousElementSibling;
    while (prevSibling) {
      if (prevSibling.tagName === element.tagName) {
        childIndex++;
      }
      prevSibling = prevSibling.previousElementSibling;
    }
    if (childIndex > 1) {
      selectorParts.push(`:nth-of-type(${childIndex})`);
    }

    return selectorParts.join('');
  }

  // Function to walk the DOM and build the selector list
  function walkDOM(node, selectors) {
    if (node.nodeType === Node.ELEMENT_NODE) {
      const selector = createSelector(node);
      selectors.push(selector);

      node.childNodes.forEach(childNode => {
        walkDOM(childNode, selectors);
      });
    }
  }

  const selectors = [];
  walkDOM(document.body, selectors);

  // Logging selectors to the console (You may need to do something else with them)
  console.log(selectors);
  return selectors;
}

